input.content:
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, Cantarell, sans-serif;
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    min-height: 100vh;
    display: flex;
    justify-content: center;
    align-items: center;
}

.container {
    text-align: center;
    background: white;
    padding: 40px;
    border-radius: 12px;
    box-shadow: 0 20px 60px rgba(0, 0, 0, 0.3);
}

h1 {
    font-size: 2.5em;
    color: #333;
    margin-bottom: 20px;
}

.status {
    margin: 20px 0;
    font-size: 1.2em;
    color: #555;
    height: 50px;
}

#turn {
    margin-bottom: 10px;
}

#turn span {
    font-weight: bold;
    color: #667eea;
}

#winner {
    font-size: 1.5em;
    color: #27ae60;
    font-weight: bold;
    min-height: 30px;
}

.board {
    display: grid;
    grid-template-columns: repeat(3, 100px);
    grid-gap: 8px;
    margin: 30px auto;
    background: #f0f0f0;
    padding: 8px;
    border-radius: 8px;
    width: fit-content;
}

.cell {
    width: 100px;
    height: 100px;
    background: white;
    border: 2px solid #ddd;
    border-radius: 6px;
    font-size: 2.5em;
    font-weight: bold;
    cursor: pointer;
    display: flex;
    justify-content: center;
    align-items: center;
    transition: all 0.3s ease;
    color: #333;
}

.cell:hover:empty {
    background: #f9f9f9;
    border-color: #667eea;
    transform: scale(1.05);
}

.cell {
    color: #667eea;
}

.cell.o {
    color: #667eea;
}

.cell.x {
    color: #e74c3c;
}

.cell.winning {
    background: #fff3cd;
    border-color: #ffc107;
    box-shadow: 0 0 10px rgba(255, 193, 7, 0.5);
}

.reset-btn {
    margin-top: 20px;
    padding: 12px 30px;
    font-size: 1em;
    background: #667eea;
    color: white;
    border: none;
    border-radius: 6px;
    cursor: pointer;
    font-weight: bold;
    transition: all 0.3s ease;
}

.reset-btn:hover {
    background: #764ba2;
    transform: translateY(-2px);
    box-shadow: 0 5px 15px rgba(102, 126, 234, 0.4);
}

.reset-btn:active {
    transform: translateY(0);
}

// 게임 상태
let gameState = {
    board: ['', '', '', '', '', '', '', '', ''],
    currentPlayer: 'O',
    gameActive: true,
    winner: null
};

// 승리 조건 (8가지)
const WINNING_CONDITIONS = [
    [0, 1, 2],
    [3, 4, 5],
    [6, 7, 8],
    [0, 3, 6],
    [1, 4, 7],
    [2, 5, 8],
    [0, 4, 8],
    [2, 4, 6]
];

// 승리 검사
function checkWin(board, player) {
    return WINNING_CONDITIONS.some(condition => {
        return condition.every(index => board[index] === player);
    });
}

// 무승부 검사
function checkDraw(board) {
    return board.every(cell => cell !== '');
}

// 게임 로직
function handleCellClick(index) {
    if (!gameState.gameActive || gameState.board[index] !== '') {
        return;
    }

    gameState.board[index] = gameState.currentPlayer;

    // 승리 검사
    if (checkWin(gameState.board, gameState.currentPlayer)) {
        gameState.winner = gameState.currentPlayer;
        gameState.gameActive = false;
        updateUI();
        return;
    }

    // 무승부 검사
    if (checkDraw(gameState.board)) {
        gameState.gameActive = false;
        updateUI();
        return;
    }

    // 턴 전환
    gameState.currentPlayer = gameState.currentPlayer === 'O' ? 'X' : 'O';
    updateUI();
}

// UI 업데이트
function updateUI() {
    const cells = document.querySelectorAll('.cell');
    cells.forEach((cell, index) => {
        cell.textContent = gameState.board[index];
        cell.classList.remove('winning', 'o', 'x');
        if (gameState.board[index] === 'O') {
            cell.classList.add('o');
        } else if (gameState.board[index] === 'X') {
            cell.classList.add('x');
        }
    });

    // 승리 셀 표시
    if (gameState.winner) {
        WINNING_CONDITIONS.forEach(condition => {
            if (condition.every(index => gameState.board[index] === gameState.winner)) {
                condition.forEach(index => {
                    cells[index].classList.add('winning');
                });
            }
        });
    }

    const turnDiv = document.getElementById('turn');
    const winnerDiv = document.getElementById('winner');

    if (gameState.winner) {
        turnDiv.style.display = 'none';
        winnerDiv.textContent = `🎉 ${gameState.winner} 승리!`;
    } else if (checkDraw(gameState.board)) {
        turnDiv.style.display = 'none';
        winnerDiv.textContent = '무승부 🤝';
    } else {
        turnDiv.style.display = 'block';
        document.getElementById('player').textContent = gameState.currentPlayer;
        winnerDiv.textContent = '';
    }
}

// 게임 초기화
function resetGame() {
    gameState = {
        board: ['', '', '', '', '', '', '', '', ''],
        currentPlayer: 'O',
        gameActive: true,
        winner: null
    };
    updateUI();
}

// DOM 초기화 (브라우저 환경에서만 실행)
if (typeof document !== 'undefined') {
    document.addEventListener('DOMContentLoaded', () => {
        const cells = document.querySelectorAll('.cell');
        cells.forEach(cell => {
            cell.addEventListener('click', (e) => {
                const index = e.target.dataset.index;
                handleCellClick(parseInt(index));
            });
        });

        const resetBtn = document.getElementById('reset');
        resetBtn.addEventListener('click', resetGame);

        updateUI();
    });
}

// 테스트용 내보내기
if (typeof module !== 'undefined' && module.exports) {
    module.exports = {
        checkWin,
        checkDraw,
        resetGame,
        handleCellClick,
        getGameState: () => ({ ...gameState }),
        setGameState: (state) => { gameState = { ...state }; }
    };
}

const { checkWin, checkDraw, resetGame, handleCellClick, getGameState, setGameState } = require('./game.js');

// 테스트 헬퍼
let passCount = 0;
let failCount = 0;

function assert(condition, testName) {
    if (condition) {
        console.log(`✓ PASS: ${testName}`);
        passCount++;
    } else {
        console.log(`✗ FAIL: ${testName}`);
        failCount++;
    }
}

function assertEqual(actual, expected, testName) {
    assert(actual === expected, `${testName} (expected: ${expected}, got: ${actual})`);
}

function assertArrayEqual(actual, expected, testName) {
    const isEqual = JSON.stringify(actual) === JSON.stringify(expected);
    assert(isEqual, testName);
}

console.log('\n=== 틱택토 게임 테스트 ===\n');

// 1. 승리 검사 - 가로줄
console.log('1. 승리 검사 - 가로줄');
let board = ['O', 'O', 'O', 'X', '', '', 'X', '', ''];
assert(checkWin(board, 'O'), '첫 번째 행 승리');

board = ['', '', '', 'X', 'X', 'X', 'O', '', ''];
assert(checkWin(board, 'X'), '두 번째 행 승리');

board = ['O', '', '', 'X', '', '', 'X', 'X', 'X'];
assert(checkWin(board, 'X'), '세 번째 행 승리');

// 2. 승리 검사 - 세로줄
console.log('\n2. 승리 검사 - 세로줄');
board = ['O', 'X', '', 'O', 'X', '', 'O', '', 'X'];
assert(checkWin(board, 'O'), '첫 번째 열 승리');

board = ['X', 'O', '', '', 'O', '', 'X', 'O', ''];
assert(checkWin(board, 'O'), '두 번째 열 승리');

board = ['', 'X', 'O', 'X', '', 'O', '', 'X', 'O'];
assert(checkWin(board, 'O'), '세 번째 열 승리');

// 3. 승리 검사 - 대각선
console.log('\n3. 승리 검사 - 대각선');
board = ['O', 'X', '', 'X', 'O', '', '', 'X', 'O'];
assert(checkWin(board, 'O'), '왼쪽 위에서 오른쪽 아래 대각선 승리');

board = ['', 'X', 'O', 'X', 'O', '', 'O', 'X', ''];
assert(checkWin(board, 'O'), '오른쪽 위에서 왼쪽 아래 대각선 승리');

// 4. 무승부 검사
console.log('\n4. 무승부 검사');
board = ['O', 'X', 'O', 'X', 'X', 'O', 'X', 'O', 'X'];
assert(checkDraw(board), '완전히 찬 보드는 무승부');

board = ['O', 'X', 'O', 'X', '', 'O', 'X', 'O', 'X'];
assert(!checkDraw(board), '빈 칸이 있으면 무승부 아님');

// 5. 턴 전환
console.log('\n5. 턴 전환');
resetGame();
let state = getGameState();
assertEqual(state.currentPlayer, 'O', '초기 플레이어는 O');

setGameState({
    board: ['', '', '', '', '', '', '', '', ''],
    currentPlayer: 'O',
    gameActive: true,
    winner: null
});
handleCellClick(0);
state = getGameState();
assertEqual(state.currentPlayer, 'X', 'O가 움직인 후 X로 턴 전환');

handleCellClick(1);
state = getGameState();
assertEqual(state.currentPlayer, 'O', 'X가 움직인 후 O로 턴 전환');

// 6. 게임 상태 업데이트
console.log('\n6. 게임 상태 업데이트');
setGameState({
    board: ['', '', '', '', '', '', '', '', ''],
    currentPlayer: 'O',
    gameActive: true,
    winner: null
});
handleCellClick(0);
state = getGameState();
assertEqual(state.board[0], 'O', 'O가 인덱스 0에 배치됨');

// 7. 빈 칸에만 배치 가능
console.log('\n7. 빈 칸에만 배치 가능');
setGameState({
    board: ['O', '', '', '', '', '', '', '', ''],
    currentPlayer: 'X',
    gameActive: true,
    winner: null
});
handleCellClick(0); // 이미 찬 칸
state = getGameState();
assertEqual(state.board[0], 'O', '이미 찬 칸에 배치 불가 - 여전히 O');
assertEqual(state.currentPlayer, 'X', '턴이 바뀌지 않음');

// 8. 승리 후 게임 종료
console.log('\n8. 승리 후 게임 종료');
setGameState({
    board: ['O', 'O', '', 'X', 'X', '', '', '', ''],
    currentPlayer: 'O',
    gameActive: true,
    winner: null
});
handleCellClick(2); // O 승리
state = getGameState();
assertEqual(state.winner, 'O', '승리자가 O로 설정됨');
assert(!state.gameActive, '승리 후 게임 종료');

// 9. 게임 초기화
console.log('\n9. 게임 초기화');
resetGame();
state = getGameState();
assertArrayEqual(state.board, ['', '', '', '', '', '', '', '', ''], '보드 초기화됨');
assertEqual(state.currentPlayer, 'O', '턴이 O로 초기화됨');
assert(state.gameActive, '게임이 활성화됨');
assertEqual(state.winner, null, '승리자 초기화됨');

// 10. 복잡한 게임 시나리오
console.log('\n10. 복잡한 게임 시나리오');
resetGame();
handleCellClick(0); // O at 0
state = getGameState();
assertEqual(state.board[0], 'O', 'O at index 0');
assertEqual(state.currentPlayer, 'X', 'X턴으로 전환');

handleCellClick(4); // X at 4
state = getGameState();
assertEqual(state.board[4], 'X', 'X at index 4');
assertEqual(state.currentPlayer, 'O', 'O턴으로 전환');

handleCellClick(8); // O at 8
state = getGameState();
assertEqual(state.board[8], 'O', 'O at index 8');

handleCellClick(1); // X at 1
state = getGameState();
assertEqual(state.board[1], 'X', 'X at index 1');

handleCellClick(2); // O at 2 - O 승리 (대각선)
state = getGameState();
assertEqual(state.winner, 'O', 'O가 대각선으로 승리');
assert(!state.gameActive, '게임이 종료됨');

// 결과 출력
console.log('\n=== 테스트 결과 ===');
console.log(`✓ 통과: ${passCount}`);
console.log(`✗ 실패: ${failCount}`);
console.log(`총합: ${passCount + failCount}`);

if (failCount === 0) {
    console.log('\n✨ 모든 테스트 통과!\n');
    process.exit(0);
} else {
    console.log('\n⚠️ 일부 테스트 실패\n');
    process.exit(1);
}
